parameters.message:
=={{ (() => {
  // 1. Obtenemos los datos limpios viajando al nodo original
  const rawEvent = $('Normalize Finding').item.json.event || $('Normalize Finding').item.json;
  const finding = rawEvent?.detail?.findings?.[0] || {};

  const nf = {
    severity: finding?.Severity?.Label || 'UNKNOWN',
    title: finding?.Title || 'Finding',
    service: finding?.ProductFields?.['aws/securityhub/CompanyName'] || 'UNKNOWN',
    resource_id: finding?.Resources?.[0]?.Id || '—',
    account: rawEvent?.account || 'unknown',
    region: rawEvent?.region || 'unknown'
  };

  // 2. Extraemos y limpiamos el JSON de la IA forzando al nodo de la IA correcto
  let ai = {};
  try {
    const aiNodeText = $('Message a model').item.json.content.parts[0].text;
    const rawText = aiNodeText.replace(/```json\n|```/g, '');
    ai = JSON.parse(rawText);
  } catch (e) {
    ai = { priority: 'UNKNOWN', rationale: 'Error parsing AI response', remediation: [], tags: [] };
  }

  // 3. Mapeamos las listas de remediación y etiquetas
  const steps = (ai.remediation || []).map(s => `<li>${s}</li>`).join('');
  const tags  = (ai.tags || []).join(', ');

  // 4. Obtenemos el ID creado en Airtable de lo que entra a este nodo actual
  const airtableId = $json.id || '';
  const airtableLine = airtableId ? `<p><b>Airtable Record ID:</b> ${airtableId}</p>` : '';

  // 5. Retornamos la plantilla HTML con los valores limpios y reales
  return `
    <h2>AWS Misconfig Alert</h2>
    <p><b>Priority:</b> ${ai.priority || 'UNKNOWN'} &nbsp; <b>Severity:</b> ${nf.severity}</p>
    <p><b>Title:</b> ${nf.title}</p>
    <p><b>Service:</b> ${nf.service} &nbsp; <b>Resource:</b> ${nf.resource_id}</p>
    <p><b>Account:</b> ${nf.account} &nbsp; <b>Region:</b> ${nf.region}</p>
    <p><b>Why:</b> ${ai.rationale || '—'}</p>
    <p><b>Remediation:</b></p>
    <ol>${steps}</ol>
    <p><b>Tags:</b> ${tags || '—'}</p>
    ${airtableLine}
    <details>
      <summary>Raw finding</summary>
      <pre style="background:#f6f8fa;padding:12px;border-radius:6px;white-space:pre-wrap">${JSON.stringify(rawEvent, null, 2)}</pre>
    </details>
  `;
})() }}

